Greedy insertion with cheapest‑cost selection per order across all existing routes plus a guaranteed empty‑route fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for shipOffset := 0; shipOffset < orderCount; shipOffset++ {
		bestIdx := -1
		bestDelta := INF_COST
		origCosts := make([]float64, dispatch.AssignsLen)
		origStates := make([]interface{}, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			origCosts[i] = assign.Cost
			saved := assign.DeepCopyState()
			origStates[i] = saved
			if assign.AddShip(total_ship+shipOffset, oris[shipOffset], dess[shipOffset]) {
				assign.GenRoute()
				if assign.Cost >= 0 {
					delta := assign.Cost - origCosts[i]
					if delta < bestDelta {
						bestDelta = delta
						bestIdx = i
					}
				}
				assign.RemoveShip(total_ship + shipOffset)
				assign.RestoreState(origStates[i])
				assign.GenRoute()
			}
		}
		fallbackIdx := -1
		if bestIdx == -1 || dispatch.AssignsLen >= MAXASSIGNS {
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					fallbackIdx = i
					break
				}
				assign := &dispatch.Assigns[i]
				if assign.StationsLen == 0 {
					fallbackIdx = i
					break
				}
			}
			if fallbackIdx != -1 && bestIdx == -1 {
				bestIdx = fallbackIdx
			}
		}
		if bestIdx >= 0 && bestIdx < MAXASSIGNS {
			target := &dispatch.Assigns[bestIdx]
			if target.StationsLen == 0 && bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			ok := target.AddShip(total_ship+shipOffset, oris[shipOffset], dess[shipOffset])
			if ok {
				target.GenRoute()
				if target.Cost < 0 {
					target.RemoveShip(total_ship + shipOffset)
					target.GenRoute()
					if fallbackIdx >= 0 && fallbackIdx < MAXASSIGNS && fallbackIdx != bestIdx {
						fb := &dispatch.Assigns[fallbackIdx]
						if fb.StationsLen == 0 && fallbackIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						if fb.AddShip(total_ship+shipOffset, oris[shipOffset], dess[shipOffset]) {
							fb.GenRoute()
						}
					}
				}
			}
		} else {
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					candidate := &dispatch.Assigns[i]
					if candidate.AddShip(total_ship+shipOffset, oris[shipOffset], dess[shipOffset]) {
						dispatch.AssignsLen++
						candidate.GenRoute()
						break
					}
				}
				candidate := &dispatch.Assigns[i]
				if candidate.StationsLen == 0 {
					if candidate.AddShip(total_ship+shipOffset, oris[shipOffset], dess[shipOffset]) {
						candidate.GenRoute()
						break
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
func (a *Assign) DeepCopyState() interface{} {
	type stateSnapshot struct {
		Cost          float64
		StationCurrent Station
		ShipIDs       []int
	}
	snap := stateSnapshot{
		Cost:           a.Cost,
		StationCurrent: a.StationCurrent,
		ShipIDs:        make([]int, len(a.ShipIDs)),
	}
	copy(snap.ShipIDs, a.ShipIDs)
	return snap
}
func (a *Assign) RestoreState(state interface{}) {
	snap, ok := state.(struct {
		Cost          float64
		StationCurrent Station
		ShipIDs       []int
	})
	if !ok {
		return
	}
	a.Cost = snap.Cost
	a.StationCurrent = snap.StationCurrent
	a.ShipIDs = make([]int, len(snap.ShipIDs))
	copy(a.ShipIDs, snap.ShipIDs)

